package com.example.datatransfer;

import io.grpc.*;

public class HeaderTokenAuthInterceptor implements ServerInterceptor {
    private final Metadata.Key<String> headerKey;
    private final String expectedToken;

    public HeaderTokenAuthInterceptor(String headerName, String expectedToken) {
        this.headerKey = Metadata.Key.of(headerName, Metadata.ASCII_STRING_MARSHALLER);
        this.expectedToken = expectedToken;
    }

    @Override
    public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
            ServerCall<ReqT, RespT> call,
            Metadata headers,
            ServerCallHandler<ReqT, RespT> next) {

        String token = headers.get(headerKey);
        if (expectedToken != null && !expectedToken.isEmpty() && !expectedToken.equals(token)) {
            call.close(Status.UNAUTHENTICATED.withDescription("Invalid or missing authorization token"), new Metadata());
            return new ServerCall.Listener<ReqT>() {};
        }
        return next.startCall(call, headers);
    }
}

